mapper.select:
SELECT CODE_GROUP, CODE_VALUE, CODE_NAME, USE_YN, UP_CODE_CODE AS UP_CODE, SORT_ORDER FROM COM_CODE WHERE 1 = 1
AND CODE_GROUP IN
#{group}
AND USE_YN = #{useYn}
AND USE_YN = 'Y'
ORDER BY CODE_GROUP, SORT_ORDER

SELECT
    ROW_NUMBER() OVER(ORDER BY m.MASTER_NO) AS RNUM,
    ,
    (SELECT CODE_NAME FROM COM_CODE WHERE CODE_GROUP = '108' AND CODE_VALUE = m.PRO_STATE)   AS PRO_STATE_NAME,
    (SELECT CODE_NAME FROM COM_CODE WHERE CODE_GROUP = '109' AND CODE_VALUE = m.PRO_STEP)    AS PRO_STEP_NAME,
    (SELECT CODE_NAME FROM COM_CODE WHERE CODE_GROUP = '102' AND CODE_VALUE = m.BIZ_SECTION) AS BIZ_SECTION_NAME
FROM BIZ_MASTER m
LEFT JOIN S1010 s ON s.MASTER_NO = m.MASTER_NO
WHERE 1 = 1

    AND m.BIZ_TITLE LIKE '%' || #{bizTitle} || '%'


    AND s.BIZ_CONTENTS LIKE '%' || #{bizContents} || '%'


    AND m.BIZ_SECTION = #{bizSection}


    AND m.BIZ_TYPE = #{bizType}


    AND m.POWER_TYPE = #{powerType}



    AND m.PRO_STEP IN

        #{step}




    AND m.PRO_STEP = #{proStep}


    AND m.PRO_STATE = #{proState}


    AND m.AREA_CODE = #{areaCode}



    AND m.REGI_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')



    AND m.REGI_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD') + 0.99999

ORDER BY m.MASTER_NO DESC

SELECT p.TASK_TYPE, p.TASK_CODE, p.PLN_START_DATE, p.PLN_TAKE_DAYS, p.PLN_END_DATE, p.PRF_START_DATE, p.PRF_TAKE_DAYS, p.PRF_END_DATE, p.LEAD_DAYS, p.DELAY_RATE, p.PREV_TASK, p.NEXT_TASK, p.TIP_DESC, p.TASK_STATUS, p.REGI_DATE, p.INWRITER_ID, p.UPDATE_DATE, p.UPWRITER_ID, t.TASK_NAME, t.TEMPLATE_YN, p.TEMPLATE_CODE FROM BIZ_PORTAL p LEFT JOIN BIZ_TASK t ON t.BIZ_TYPE = p.TASK_TYPE AND t.TASK_CODE = p.TASK_CODE WHERE 1 = 1
AND p.MASTER_NO = #{masterNo}
AND NOT ( p.TASK_TYPE = '109' AND p.TASK_CODE IN
#{code}
)
ORDER BY p.TASK_TYPE, CASE WHEN p.TASK_CODE LIKE 'S%' THEN 0 ELSE 1 END, -- S(사업발굴) → D(사업개발) 순서 p.TASK_CODE

