mapper.select:
/* selectBizTaskList 공정표 목록 조회 */ SELECT A.MASTER_NO , A.TASK_TYPE , A.TASK_TYPE_NAME , A.TASK_CODE , A.TASK_CODE_ORD , A.TASK_NAME , A.TAKE_DAYS -- 소요기간(BIZ_TASK 기준) , A.PLN_START_DATE -- 계획 시작일자 , A.PLN_TAKE_DAYS -- 계획 소요기간 , A.PLN_END_DATE -- 계획 종료일자 , A.PRF_START_DATE -- 실적 시작일자 , A.PRF_TAKE_DAYS -- 실적 소요기간 , A.PRF_END_DATE -- 실적 완료일자 , A.LEAD_DAYS -- 평균소요시간 , A.DELAY_RATE -- 평균지연확률 , A.PREV_TASK -- 이전업무 , A.NEXT_TASK -- 다음업무 , A.TIP_DESC -- TIP 설명 , A.TASK_STATUS -- 진행 완료 여부 (Y/N/S/T/H) , A.TEMPLATE_YN -- 진행률: 실적/계획 소요기간 비율 (둘 중 하나라도 0이면 0 반환) , CASE WHEN NVL(PLN_TAKE_DAYS,0)!=0 AND NVL(PRF_TAKE_DAYS,0)!=0 THEN ROUND(CAST(PRF_TAKE_DAYS AS FLOAT)/CAST(PLN_TAKE_DAYS AS FLOAT)*100,0) ELSE 0 END AS COMPLETE , (SELECT COUNT(TASK_CODE ) AS FILE_CNT FROM BIZ_ATTACH_FILE F WHERE A.MASTER_NO=F.MASTER_NO AND A.TASK_TYPE=F.TASK_TYPE AND A.TASK_CODE=F.TASK_CODE AND F.USE_YN='Y' ) AS FILE_CNT , ( SELECT bm.BIZ_TITLE FROM BIZ_MASTER bm WHERE bm.MASTER_NO=A.MASTER_NO ) AS BIZ_TITLE FROM ( SELECT A.MASTER_NO , A.TASK_TYPE -- '109'(사내절차)는 코드그룹명 없으므로 하드코딩 , CASE WHEN A.TASK_TYPE='109' THEN '사내절차' ELSE CM.CODE_GROUP_NAME END TASK_TYPE_NAME , A.TASK_CODE -- 정렬용 가상 컬럼: S→A 변환, D→B 변환으로 S→D 순서 보장 , CASE WHEN A.TASK_TYPE='109' AND SUBSTR(A.TASK_CODE,1,1)='S' THEN 'A'||SUBSTR(A.TASK_CODE,2,LENGTH(A.TASK_CODE)-1 ) WHEN A.TASK_TYPE='109' AND SUBSTR(A.TASK_CODE,1,1)='D' THEN 'B'||SUBSTR(A.TASK_CODE,2,LENGTH(A.TASK_CODE)-1 ) WHEN A.TASK_TYPE='109' THEN 'C'||SUBSTR(A.TASK_CODE,2,LENGTH(A.TASK_CODE)-1 ) ELSE '' ---- A.TASK_CODE END TASK_CODE_ORD , CMD.TASK_NAME -- 2차분류 태스크명 , CMD.TAKE_DAYS -- 소요기간(BIZ_TASK 기준) , A.PLN_START_DATE , NVL(A.PLN_TAKE_DAYS,CMD.TAKE_DAYS) AS PLN_TAKE_DAYS -- 계획 소요기간 없으면 기준값 사용 , A.PLN_END_DATE , A.PRF_START_DATE , A.PRF_TAKE_DAYS , A.PRF_END_DATE , A.LEAD_DAYS , A.DELAY_RATE , A.PREV_TASK , A.NEXT_TASK , A.TIP_DESC , A.TASK_STATUS , CMD.TEMPLATE_YN FROM BIZ_PORTAL A INNER JOIN COME_CODE_GROUP CM ON A.TASK_TYPE=CM.CODE_GROUP INNER JOIN BIZ_TASK CMD ON A.TASK_TYPE=CMD.BIZ_TYPE AND A.TASK_CODE=CMD.TASK_CODE AND CMD.TEMPLATE_YN='N' WHERE A.MASTER_NO=#{masterNo} AND A.TASK_STATUS!='C'
AND A.TASK_TYPE = #{taskType}
AND A.TASK_CODE = #{taskCode}
) A ORDER BY A.TASK_TYPE, A.TASK_CODE_ORD,A.PLN_START_DATE

mapper.update:
UPDATE BIZ_PORTAL
   SET PLN_START_DATE = #{plnStartDate}
     , PLN_END_DATE   = #{plnEndDate}
     , PLN_TAKE_DAYS  = #{plnTakeDays}
     , PRF_START_DATE = #{prfStartDate}
     , PRF_END_DATE   = #{prfEndDate}
     , PRF_TAKE_DAYS  = #{prfTakeDays}
     , LEAD_DAYS      = #{leadDays}
     , DELAY_RATE     = #{delayRate}
     , TIP_DESC       = #{tipDesc}
     , UPDATE_DATE    = SYSDATE
     , UPWRITER_ID    = #{writerId}
WHERE MASTER_NO = #{masterNo}
  AND TASK_TYPE = #{taskType}
  AND TASK_CODE = #{taskCode}

mapper.select:
SELECT 0 AS CHK, A.MASTER_NO , A.TASK_TYPE -- '109'(사내절차)는 코드그룹명 없으므로 하드코딩 , CASE WHEN A.TASK_TYPE='109' THEN '사내절차' ELSE CM.CODE_GROUP_NAME END TASK_TYPE_NAME , A.TASK_CODE -- 정렬용 가상 컬럼: S→A 변환, D→B 변환으로 S→D 순서 보장 , CASE WHEN A.TASK_TYPE='109' AND SUBSTR(A.TASK_CODE,1,1)='S' THEN 'A'||SUBSTR(A.TASK_CODE,2,LENGTH(A.TASK_CODE)-1 ) WHEN A.TASK_TYPE='109' AND SUBSTR(A.TASK_CODE,1,1)='D' THEN 'B'||SUBSTR(A.TASK_CODE,2,LENGTH(A.TASK_CODE)-1 ) WHEN A.TASK_TYPE='109' THEN 'C'||SUBSTR(A.TASK_CODE,2,LENGTH(A.TASK_CODE)-1 ) ELSE '' --A.TASK_CODE END TASK_CODE_ORD , CMD.TASK_NAME -- 2차분류 태스크명 , A.ATTACH_FILE_SEQ , A.ORDER_NO , A.FILE_SEQ , A.FILE_NAME , A.FILE_SIZE , A.TITLE , A.DELETE_ID , A.USE_YN , TO_CHAR( A.WRITE_DATE , 'YYYY-MM-DD' ) WRITE_DATE , A.WRITER_ID , E.NAME AS WRITER_NAME FROM BIZ_ATTACH_FILE A INNER JOIN COME_CODE_GROUP CM ON A.TASK_TYPE=CM.CODE_GROUP INNER JOIN BIZ_TASK CMD ON A.TASK_TYPE=CMD.BIZ_TYPE AND A.TASK_CODE=CMD.TASK_CODE AND CMD.TEMPLATE_YN='N' INNER JOIN BIZ_PORTAL BP ON A.MASTER_NO=BP.MASTER_NO AND A.TASK_TYPE=BP.TASK_TYPE AND A.TASK_CODE=BP.TASK_CODE AND BP.TASK_STATUS!='C' LEFT OUTER JOIN EMPLOYEE E ON A.WRITER_ID=E.EMPNO WHERE A.FILE_GUBUN IN ('A','R') AND A.MASTER_NO LIKE #{masterNo}||'%' AND A.TASK_TYPE LIKE #{searchTaskType}||'%' AND A.TASK_CODE LIKE SUBSTR(#{searchTaskCode},4)||'%'
AND TO_CHAR( A.WRITE_DATE , 'YYYY-MM-DD' ) BETWEEN #{startDate} AND #{endDate}
AND A.TITLE LIKE CASE WHEN #{searchType}='bizTitle' THEN '%'||#{searchText}||'%' ELSE '%' END AND A.FILE_NAME LIKE CASE WHEN #{searchType}='bizFile' THEN '%'||#{searchText}||'%' ELSE '%' END ORDER BY A.MASTER_NO, A.TASK_TYPE--, A.TASK_CODE_ORD

SELECT
TO_CHAR(REGI_DATE, 'YYYY') TO_CHAR(REGI_DATE, 'YYYYMM') AS VDATE, COUNT(*) AS CNT,
PRO_STATE PRO_STEP CONTINENT_CODE INFO_METHOD BIZ_SECTION BIZ_TYPE BIZ_FORM NULL AS Y_VALUE,
PRO_STATE PRO_STEP CONTINENT_CODE INFO_METHOD BIZ_SECTION BIZ_TYPE BIZ_FORM NULL AS X_VALUE FROM BIZ_MASTER WHERE 1=1 AND WRITER_ID != '94103665' AND PRO_STATE IS NOT NULL
AND TO_CHAR(REGI_DATE, 'YYYY') >= #{stYear} AND TO_CHAR(REGI_DATE, 'YYYY') <= #{endYear}
AND TO_CHAR(REGI_DATE, 'YYYYMM') >= #{stYear} AND TO_CHAR(REGI_DATE, 'YYYYMM') <= #{endYear}
AND PRO_STATE IN #{v}
AND PRO_STEP IN #{v}
AND INFO_METHOD IN #{v}
AND BIZ_SECTION IN #{v}
AND BIZ_TYPE IN #{v}
AND BIZ_FORM IN #{v}
AND CONTINENT_CODE = #{continentCode}
AND NATION_CODE = #{nationCode}
GROUP BY
TO_CHAR(REGI_DATE, 'YYYY') TO_CHAR(REGI_DATE, 'YYYYMM')
, PRO_STATE PRO_STEP CONTINENT_CODE INFO_METHOD BIZ_SECTION BIZ_TYPE BIZ_FORM
, PRO_STATE PRO_STEP CONTINENT_CODE INFO_METHOD BIZ_SECTION BIZ_TYPE BIZ_FORM
ORDER BY VDATE, Y_VALUE, X_VALUE
